import logo from './logo.svg';
import './App.css';
import React, { useState, useEffect } from "react";
import images from './images'

import { database } from "./firebaseConfig";
import Josh from "./components/josh"
import joshwhistle from "./other-assets/joshed.mp3";
import AudioPlayer from "./components/audio-player"
import Photocards from "./components/photocards"
import Adoptable from "./components/adoptable"
import About from './components/about';
import fanlistings from './fanlistings';
import { collection, doc, setDoc, onSnapshot  } from "firebase/firestore"; 


function App() {
  const [status, setStatus] = useState({
    date: 'Loading...', 
    message: 'Loading...'});

    const [josh, setJosh] = useState(false);

    const [main, setMain] = useState(true);
    const [about, setAbout] = useState(false);
    const listFansites = fanlistings.map(temp =><a  target="_blank" rel="noopener noreferrer" href={temp.url}><img src={temp.thumbnail}/></a> );



  useEffect(
    () =>
      onSnapshot(collection(database, "statuses"), (snapshot) => {
        snapshot.forEach((doc) => {
          let tempstatus = {
            date: doc.data().date,
            message: doc.data().message
          }
          setStatus(tempstatus);
        });
      }),
    []
  );

  let whistle = new Audio(joshwhistle);

  const handleJosh = () =>{
    setJosh(true);
    whistle.play();
    
    setTimeout(function() { setJosh(false); }, 3500);
    setTimeout(function() { whistle.pause(); }, 3560);

  }

  const handlePages = (pageName) =>{
    setMain(false);
    setAbout(false);
    if (pageName == "about"){
      setAbout(true);
    }
    if (pageName == "main"){
      setMain(true);
    }
  }



  return (
    <div className='site-container'>
        <div className='page-controller'>
        <div className= {main ? "main-page-top-wrapper" :  "page-hidden"}>
          <img id="sleepykitty" src={images.sleepykitty.url}></img>
          
          <div className='left-column'>
          <div className = "headshot">
            <div className = "icon">
                <img id = "binari" src = {images.binari.url}></img>
                {/* <img id = "frame" src = {frame}></img> */}
            </div>
            <div class = "attr">
                <a href="https://www.webtoons.com/en/fantasy/the-dark-lords-confession/list?title_no=4464">icon: the dark lord's confession</a>   
            </div>
          </div>

        {/* <!-- TITLE --> */}
        <div className = "title">
            <h1>🍓 marketchipping 🍓</h1>
        </div>

        {/* <!-- LINKS --> */}
        <div className = "links">
          <div className= {josh ?'popupWrapperActive':'popupWrapperHidden'} >
          <Josh josh={josh}/>
        </div>
            <p>links</p>
            <div className = "linkswrapper">
                <div onClick={()=>handlePages("about")}>info</div>
                <div  onClick={() => handleJosh()}>josh</div>
            </div>
        </div>

        <div id="adopt-positioner">
          <Adoptable/>
        </div>
        </div>

        <div className="mainmenu">
          <div className="status-wrapper">
          <p id="status-title">status</p>
            <div className = "status">
              <div id = "status-details">{status.date}</div>
              <div className = "status-message" id="actual-homepage-status">
                <p>{status.message}</p>
              </div>
            </div>
          </div>
          <div className = "guestbook">
               <p>guestbook --{'>'} </p> 
              <a href="https://marketchipping.atabook.org/">
              <img src={images.mail.url}></img>
              </a>
            </div>
          <div className='badges-webrings'>
            <p id="webrings-title">fanlistings</p>
            {/* <p id = "badgedesc">Check in later to see!</p> */}
            <div id='fansites'>
              {listFansites}
            </div>
            <div id="birds">
              {/* <img src={images.birdgif.url}></img> */}

            </div>

          </div>

        </div>

      

        {/* <!-- OTHJERS --> */}
        <div className = "other">
            <img id="strawberrygif1" src={images.strawberrygif.url}></img>
            <div id = "photocards-positioner">
              <Photocards/>
            </div>
            
            <AudioPlayer/>
            {/* <!-- BADGES / DOODADS --> */}
            <div className = "badges">
                <img src="https://images-wixmp-ed30a86b8c4ca887773594c2.wixmp.com/f/819c254f-4a99-42fe-aadc-6b8dc100389a/d2dl7yb-1894234e-6140-411d-bf0b-3cc50d3fc624.gif?token=eyJ0eXAiOiJKV1QiLCJhbGciOiJIUzI1NiJ9..-_ownc3QpLHF6toY3j-PDZ-Iz-QAxp0Cbce71VohWnU" alt="persona 3 badge"></img>
                <img src="https://images-wixmp-ed30a86b8c4ca887773594c2.wixmp.com/f/60904c9a-3161-4cc0-a776-9139a39fbbc9/d3f60lb-55148214-0c41-499f-96ec-be83497198fc.gif?token=eyJ0eXAiOiJKV1QiLCJhbGciOiJIUzI1NiJ9..6UdEqHhu5iyv-qVN9yTp9hY97KbAUd0flStX-j7CP4Y" alt="persona 3 badge"></img>
                <img src="https://images-wixmp-ed30a86b8c4ca887773594c2.wixmp.com/f/4b58ca07-d645-4380-aa97-78886aad5819/d2nfyfz-c74a9e17-38b6-40b2-9709-5740a53d797f.png/v1/fill/w_99,h_56,q_80,strp/p4_yosuke_stamp_c__by_crescentmarionette_d2nfyfz-fullview.jpg?token=eyJ0eXAiOiJKV1QiLCJhbGciOiJIUzI1NiJ9..K4aw61R3iaq84K1tjc7UkF6s4PVfeg8O4Vojya5q0-E"></img>
                <img src={images.techcat2.url}></img>
            </div>
            <img id="strawberrygif2" src={images.strawberrygif.url}></img>
        </div>
        </div>
        <About about={about} handlePages={handlePages}/>
      </div>
    </div>

  );
}

export default App;
